variable "company_name" {
  type = string

  validation {
    condition     = length(var.company_name) >= 3 && length(var.company_name) <= 20
    error_message = "Company name must be between 3 and 20 characters long."
  }
}

variable "company_name" {
  type = string

  validation {
    condition     = !can(regex("[^a-zA-Z0-9]", var.company_name))
    error_message = "Company name cannot contain special characters."
  }
}

locals {
  allowed_environments = ["dev", "stage", "prod"]
}

variable "environment" {
  type = string

  validation {
    condition     = contains(local.allowed_environments, var.environment)
    error_message = "Environment must be one of: dev, stage, prod."
  }
}

variable "aws_region" {
  type = string

  validation {
    condition     = startswith(var.aws_region, "us-")
    error_message = "AWS region must start with us-."
  }
}

resource "aws_instance" "web" {
  ami           = data.aws_ami.selected.id
  instance_type = var.instance_type

  lifecycle {
    precondition {
      condition     = data.aws_ami.selected.architecture == "x86_64"
      error_message = "The selected AMI must use x86_64 architecture."
    }
  }
}

resource "aws_instance" "web" {
  ami           = data.aws_ami.selected.id
  instance_type = var.instance_type
  subnet_id     = aws_subnet.public.id

  lifecycle {
    postcondition {
      condition     = self.public_ip != null && self.public_ip != ""
      error_message = "The EC2 instance must have a public IP address after creation."
    }
  }
}

