check "subnet_count" {
  assert {
    condition     = length(data.aws_subnets.current.ids) == var.availability_zones * 2
    error_message = "The number of subnets in the VPC does not match the expected public + private subnet count."
  }
}

check "ec2_power_status" {
  data "aws_instance" "web_status" {
    instance_id = aws_instance.web.id
  }

  assert {
    condition     = data.aws_instance.web_status.instance_state == "running"
    error_message = "The EC2 instance is not in the running state."
  }
}

variables {
  environment        = "dev"
  aws_region         = "us-east-1"
  availability_zones = 2
}

run "good_plan" {
  command = plan
}

run "bad_environment" {
  command = plan

  variables {
    environment = "qa"
  }

  expect_failures = [var.environment]
}

run "setup" {
  command = apply
}

run "test_site" {
  command = apply

  module {
    source = "../setup/http_test"
  }

  variables {
    url = run.setup.application_url
  }

  assert {
    condition     = data.http.site_check.status_code == 200
    error_message = "The deployed site did not return HTTP 200."
  }
}

