data "<data_source_type>" "<name_label>" {
  # arguments specific to the data source
}

data "aws_availability_zones" "available" {
  state = "available"
}

variable "availability_zones_count" {
  type = number
}

resource "aws_subnet" "public" {
  count             = var.availability_zones_count
  vpc_id            = aws_vpc.main.id
  availability_zone = data.aws_availability_zones.available.names[count.index]
}

data "aws_ami" "amazon_linux_2" {
  owners      = ["amazon"]
  most_recent = true

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

resource "aws_instance" "app" {
  ami = data.aws_ami.amazon_linux_2.id
}

data "cloudinit_config" "user_data" {
  gzip          = false
  base64_encode = false

  part {
    content_type = "text/x-shellscript"
    content = templatefile("${path.module}/templates/startup.sh.tftpl", {
      company_name = var.company_name
      environment  = var.environment
    })
  }
}

resource "aws_instance" "app" {
  user_data = data.cloudinit_config.user_data.rendered
}

data "terraform_remote_state" "network" {
  backend = "s3"

  config = {
    bucket = "my-network-state-bucket"
    key    = "taco-wagon-net.tfstate"
    region = "us-west-2"
  }
}

resource "aws_security_group" "web" {
  vpc_id = data.terraform_remote_state.network.outputs.vpc_id
}

data "tfe_outputs" "networking" {
  organization = "my-org"
  workspace    = "taco-wagon-net"
}

# Non-sensitive outputs
# data.tfe_outputs.networking.nonsensitive_values.vpc_id

resource "aws_ssm_parameter" "vpc_id" {
  name           = "/taco-wagon-networking/${var.environment}/vpc-id"
  description    = "VPC ID for the taco wagon app"
  type           = "String"
  insecure_value = aws_vpc.main.id

  tags = {
    environment = var.environment
    application = "taco-wagon"
  }
}

resource "aws_ssm_parameter" "public_subnet_ids" {
  name           = "/taco-wagon-networking/${var.environment}/public-subnet-ids"
  description    = "Public subnet IDs for the taco wagon app"
  type           = "StringList"
  insecure_value = join(",", aws_subnet.public[*].id)

  tags = {
    environment = var.environment
    application = "taco-wagon"
  }
}

variable "network_parameter_path" {
  type = string
}

data "aws_ssm_parameter" "network" {
  for_each = toset([
    "vpc-id",
    "public-subnet-ids"
  ])

  name = "${var.network_parameter_path}/${var.environment}/${each.value}"
}

resource "aws_security_group" "web" {
  vpc_id = data.aws_ssm_parameter.network["vpc-id"].insecure_value
}

resource "aws_instance" "app" {
  subnet_id = split(",", data.aws_ssm_parameter.network["public-subnet-ids"].insecure_value)[0]
}
